import React from "react";
import "../styles/About.css"; // Import the CSS file

const teamMembers = [
  {
    name: "Anshuman Pandey",
    image: "/images/manicon.png",
    description: "I am the student of TIT MAIN. Currently pursuing B.Tech from CSE-DS.",
  },
  {
    name: "Ajita Bajpai",
    image: "/images/manicon.png",
    description: "I am the student of TIT MAIN. Currently pursuing B.Tech from CSE-DS.",
  },
  {
    name: "Dimpi Malghati",
    image: "/images/images.png",
    description: "I am the student of TIT MAIN. Currently pursuing B.Tech from CSE-DS.",
  },
  {
    name: "Arpita Sthapak",
    image: "/images/manicon.png",
    description: "I am the student of TIT MAIN. Currently pursuing B.Tech from CSE-DS.",
  }
  
];

const About = () => {
  return (
    <div className="about">
    <div><h2 className="team-title">About Us</h2>
    <div className="container">
  <p className="about-content">
    <h2>Welcome to Travelo</h2>
    <p>Welcome to Travelo, your reliable partner in bus travel reservations!</p>
    <p>At Travelo, we are passionate about making your journey seamless, comfortable, and stress-free. Whether you’re planning a weekend getaway, a business trip, or a family vacation, we provide an easy-to-use platform that allows you to book bus tickets with just a few clicks.</p>
    
    <p>Our mission is simple: to connect passengers with trusted bus operators, offering a convenient, safe, and affordable travel experience. With a user-friendly interface, you can easily search for buses, compare schedules, and secure your seat in minutes. We strive to provide comprehensive travel options, making sure you get the best routes, timings, and prices for your trip.</p>
    
    <h3>Why Choose Us?</h3>
    <ul>
      <li><span className="highlight">Convenience</span>: Book tickets on-the-go with our easy-to-use web app.</li>
      <li><span className="highlight">Variety</span>: Choose from a wide range of bus operators and routes.</li>
      <li><span className="highlight">Affordable</span>: Competitive prices with no hidden fees.</li>
      <li><span className="highlight">Customer Support</span>: Our dedicated team is available to assist you at every step of the way.</li>
      <li><span className="highlight">Security</span>: Enjoy secure and safe transactions for a worry-free booking process.</li>
    </ul>
    
    <p>We are committed to improving your travel experience by continually enhancing our platform and expanding our services. Thank you for choosing Travelo, where your journey begins with us!</p>
    
    <a href="#" className="button">Get Started</a>
  </p>
</div>
</div>
      <div className="team-section">
        <h2 className="team-title">Our Team</h2>
        <div className="team-members">
          {teamMembers.map((member, index) => (
            <div key={index} className="team-member-card">
              <div className="team-member-content">
                <img
                  className="team-member-image"
                  src={member.image}
                  alt={member.name}
                />
                <h3 className="team-member-name">{member.name}</h3>
                <p className="team-member-description">{member.description}</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default About;
